// Classic deadlock example (two threads, two locks)
import java.util.concurrent.locks.ReentrantLock;

ReentrantLock lockA = new ReentrantLock();
ReentrantLock lockB = new ReentrantLock();

// Thread 1: acquires A then B
new Thread(() -> {
    lockA.lock();
    Thread.sleep(50); // holds A, waits for B
    lockB.lock();
}).start();

// Thread 2: acquires B then A
new Thread(() -> {
    lockB.lock();
    Thread.sleep(50); // holds B, waits for A
    lockA.lock();
}).start();
// Both threads wait forever — deadlock!

// Prevention: enforce consistent lock ordering (always lock A before B)

-- Classic ACID example: bank transfer
BEGIN TRANSACTION;

  -- Atomicity: both must succeed or both roll back
  UPDATE accounts SET balance = balance - 500 WHERE id = 1;
  UPDATE accounts SET balance = balance + 500 WHERE id = 2;

  -- Consistency: CHECK constraint prevents negative balance
  -- enforced automatically by the DB

COMMIT;
-- On crash before COMMIT: entire transaction is rolled back
-- Durability: after COMMIT, WAL log ensures data survives crash

-- Isolation level example:
SET TRANSACTION ISOLATION LEVEL REPEATABLE READ;
BEGIN;
  SELECT balance FROM accounts WHERE id = 1; -- sees snapshot
  -- another transaction cannot change id=1 until we commit
COMMIT;

-- Without index: full table scan O(N)
EXPLAIN SELECT * FROM users WHERE email = 'test@test.com';
-- Seq Scan on users (cost=0.00..1840.00 rows=100000)

-- Create index
CREATE INDEX idx_users_email ON users(email);

-- With index: B-Tree lookup O(log N)
EXPLAIN SELECT * FROM users WHERE email = 'test@test.com';
-- Index Scan using idx_users_email (cost=0.43..8.45 rows=1)

-- Composite index: useful for queries filtering on both columns
CREATE INDEX idx_orders_user_date ON orders(user_id, created_at);
-- Good for: WHERE user_id = 5 ORDER BY created_at
-- Bad for:  WHERE created_at > '2024-01-01' (leading column rule)

-- Partial index: only index active users
CREATE INDEX idx_active_users ON users(email) WHERE active = true;

# Singleton
class DatabaseConnection:
    _instance = None
    def __new__(cls):
        if cls._instance is None:
            cls._instance = super().__new__(cls)
            cls._instance.connect()
        return cls._instance

