# Observer
class EventEmitter:
    def __init__(self):
        self._listeners = {}
    def on(self, event, fn):
        self._listeners.setdefault(event, []).append(fn)
    def emit(self, event, *args):
        for fn in self._listeners.get(event, []):
            fn(*args)

emitter = EventEmitter()
emitter.on('login', lambda u: print(f'{u} logged in'))
emitter.emit('login', 'Alice')

# Inheritance (is-a)
class Animal:
    def eat(self): print('eating')

class Dog(Animal):  # Dog is-an Animal
    def bark(self): print('woof')

# Problem: what if we add Robot? Robot.eat() makes no sense.
# Deep hierarchies get fragile fast.

# Composition (has-a) - preferred
class SwimAbility:
    def swim(self): print('swimming')

class FlyAbility:
    def fly(self): print('flying')

class Duck:
    def __init__(self):
        self.swimmer = SwimAbility()  # has-a
        self.flyer = FlyAbility()     # has-a
    def swim(self): self.swimmer.swim()
    def fly(self): self.flyer.fly()

# Now we can compose Robot with SwimAbility without inheriting Animal

from collections import OrderedDict

class LRUCache:
    def __init__(self, capacity: int):
        self.capacity = capacity
        self.cache = OrderedDict()  # maintains insertion/access order

    def get(self, key: str):
        if key not in self.cache:
            return -1
        self.cache.move_to_end(key)  # mark as recently used
        return self.cache[key]

    def put(self, key: str, value):
        if key in self.cache:
            self.cache.move_to_end(key)
        self.cache[key] = value
        if len(self.cache) > self.capacity:
            self.cache.popitem(last=False)  # evict least recently used

cache = LRUCache(2)
cache.put('a', 1)
cache.put('b', 2)
cache.get('a')      # 'a' is now most recently used
cache.put('c', 3)   # evicts 'b' (least recently used)
